    Assert.True(result.Chunks.Count >= 2, "expected at least 2 elements");
    Assert.True((result.Chunks ?? new()).All(c => !string.IsNullOrEmpty(c.Content)));
    Assert.True(result.ChunksHaveHeadingContext);
    Assert.True(result.FirstChunkStartsWithHeading);

        }

